    return;
  }

  if (!value || typeof value !== "object") {
    return;
  }

  if (nodeUtilTypes.isProxy(value)) {
    addReason(reasons, "hostile-caller-object");
    return;
  }

  if (!Array.isArray(value) && !isPlainRecord(value)) {
    if (isSchemaValidatedScalarObject(trail)) {
      return;
    }

    addReason(reasons, "hostile-caller-object");
    return;
  }

  if (depth > SCAN_BOUNDS.maxDepth) {
    addReason(reasons, "hostile-caller-object");
    return;
  }

  if (seen.has(value)) {
    return;
  }

  seen.add(value);
  budget.objectCount += 1;

  if (budget.objectCount > SCAN_BOUNDS.maxObjectCount) {
    addReason(reasons, "hostile-caller-object");
    return;
  }

  let descriptors;

  try {
    descriptors = Object.getOwnPropertyDescriptors(value);
  } catch {
    addReason(reasons, "hostile-caller-object");
    return;
  }

  scanDescriptorValues(
    descriptors,
    trail,
    reasons,
    context,
    schemaState,
    Array.isArray(value)
  );

  for (const [key, descriptor] of descriptorEntries(descriptors)) {
    if (
      typeof key === "symbol" ||
      hasAccessorDescriptor(descriptor) ||
      hasCallableDescriptor(descriptor) ||
      isSchemaMissingValueDescriptor(key, trail, descriptor.value)
    ) {
      continue;
    }

    scanNestedSafety(
      descriptor.value,
      [...trail, normalizeFieldName(key)],
      reasons,
      context,
      schemaState,
      seen,
      depth + 1,
      budget
    );
  }
