function scanRawMarkersDeep(value, reasons) {
  const seen = new WeakSet();
  const stack = [value];

  while (stack.length > 0) {
    const current = stack.pop();

    if (rawMarkerValue(current)) {
      addReason(reasons, "raw-marker-present");
      continue;
    }

    if (
      !current ||
      (typeof current !== "object" && typeof current !== "function") ||
      nodeUtilTypes.isProxy(current) ||
      seen.has(current)
    ) {
      continue;
    }

    seen.add(current);

    let descriptors;

    try {
      descriptors = Object.getOwnPropertyDescriptors(current);
    } catch {
      continue;
    }

    const entries = descriptorEntries(descriptors);

    for (let index = entries.length - 1; index >= 0; index -= 1) {
      const [key, descriptor] = entries[index];

      if (rawMarkerValue(key)) {
        addReason(reasons, "raw-marker-present");
      }

      if (hasAccessorDescriptor(descriptor) || hasCallableDescriptor(descriptor)) {
        continue;
      }

      stack.push(descriptor.value);
    }
